import{c as e,Q as a,j as i,m as r}from"./chunks/framework.BXc4yaFE.js";const g=JSON.parse('{"title":"COMPOSITE-STEM: Expert-Curated STEM Benchmark","description":"","frontmatter":{"title":"COMPOSITE-STEM: Expert-Curated STEM Benchmark","authors":"Kyle Waters, Lucas Nuzzi, Tadhg Looram, Alessandro Tomasiello, Ariel Ghislain Kemogne Kamdoum, Bikun Li, Damien Sileo, Egor Kretov, Francesco Fournier-Facio, Georgios Soloupis, Haile Kassahun, Hew Wolff, Jiaqi Cai, Lianghui Li, Marc Roth, Mohinder Naiya, Naixu Guo, Qicheng Tang, Richard Wheeler, Samuele Sala, Serguei Popov, Steven Dillmann, Yuqi Li","published":"2026-04-10T00:00:00.000Z","source":"https://arxiv.org/abs/2604.09836"},"headers":[],"relativePath":"research/papers/2026-04-10-composite-stem-expert-curated.md","filePath":"research/papers/2026-04-10-composite-stem-expert-curated.md","lastUpdated":1779901665000}'),o={name:"research/papers/2026-04-10-composite-stem-expert-curated.md"};function n(s,t,l,d,c,u){return a(),i("div",null,[...t[0]||(t[0]=[r('<h1 id="composite-stem-70-expert-curated-agentic-tasks-across-physics-biology-chemistry-and-math" tabindex="-1">COMPOSITE-STEM: 70 Expert-Curated Agentic Tasks Across Physics, Biology, Chemistry, and Math <a class="header-anchor" href="#composite-stem-70-expert-curated-agentic-tasks-across-physics-biology-chemistry-and-math" aria-label="Permalink to &quot;COMPOSITE-STEM: 70 Expert-Curated Agentic Tasks Across Physics, Biology, Chemistry, and Math&quot;">​</a></h1><p><strong>Authors</strong>: Kyle Waters, Lucas Nuzzi, Tadhg Looram (PortexAI), Alessandro Tomasiello, Ariel Ghislain Kemogne Kamdoum, Bikun Li, Damien Sileo, Egor Kretov, Francesco Fournier-Facio, Georgios Soloupis, Haile Kassahun, Hew Wolff, Jiaqi Cai, Lianghui Li, Marc Roth, Mohinder Naiya, Naixu Guo, Qicheng Tang, Richard Wheeler, Samuele Sala, Serguei Popov, Steven Dillmann, Yuqi Li<br><strong>Published</strong>: April 10, 2026 (v1); revised April 16, 2026 (v2)<br><strong>Source</strong>: <a href="https://arxiv.org/abs/2604.09836" target="_blank" rel="noreferrer">https://arxiv.org/abs/2604.09836</a><br><strong>arXiv ID</strong>: 2604.09836<br><strong>Categories</strong>: cs.AI, cs.CL, cs.LG<br><strong>Dataset</strong>: <a href="https://huggingface.co/datasets/portex/COMPOSITE-STEM" target="_blank" rel="noreferrer">https://huggingface.co/datasets/portex/COMPOSITE-STEM</a><br><strong>Code</strong>: <a href="https://github.com/portex-ai/portex-composit-harbor-adapter" target="_blank" rel="noreferrer">https://github.com/portex-ai/portex-composit-harbor-adapter</a></p><h2 id="abstract" tabindex="-1">Abstract <a class="header-anchor" href="#abstract" aria-label="Permalink to &quot;Abstract&quot;">​</a></h2><p>AI agents hold growing promise for accelerating scientific discovery; yet, a lack of frontier evaluations hinders adoption into real workflows. This work introduces COMPOSITE-STEM, a benchmark featuring 70 expert-written tasks spanning physics, biology, chemistry, and mathematics, curated by doctoral-level researchers. The benchmark combines exact-match grading with criterion-based rubrics and an LLM-as-jury grading protocol to assess scientifically valid outputs. Using an adapted multimodal Terminus-2 agent harness within the Harbor evaluation framework, four frontier models were evaluated, with the top performer (Claude-opus-4.6) achieving 21.4% accuracy (Pass@1). All tasks are open-sourced to support reproducibility and further research.</p><h2 id="_1-introduction" tabindex="-1">1. Introduction <a class="header-anchor" href="#_1-introduction" aria-label="Permalink to &quot;1. Introduction&quot;">​</a></h2><p>Existing expert-grade benchmarks for AI evaluation have been reaching saturation: frontier models increasingly score near ceiling on datasets like GPQA and HLE, making it difficult to distinguish capability differences among top systems. Meanwhile, practical scientific workflows require agents to reason, compute, and interact with domain-specific tools in executable environments — capabilities not tested by static question-answering formats.</p><p>COMPOSITE-STEM addresses this gap by introducing a cross-domain STEM task bundle compatible with Harbor agentic evaluation. The benchmark evaluates &quot;more than isolated scientific reasoning by pairing expert-authored tasks with executable environments and flexible grading.&quot; Tasks require agents to write and execute code, install scientific packages, interpret results, and produce answers verified against expert-curated rubrics.</p><p>The benchmark&#39;s key design goal is difficulty calibration for frontier systems: the top performer achieves only 21.4%, indicating substantial headroom for improvement and reliable discrimination between model capabilities.</p><h3 id="_1-1-positioning-within-benchmark-evolution" tabindex="-1">1.1 Positioning Within Benchmark Evolution <a class="header-anchor" href="#_1-1-positioning-within-benchmark-evolution" aria-label="Permalink to &quot;1.1 Positioning Within Benchmark Evolution&quot;">​</a></h3><p>The paper contextualizes COMPOSITE-STEM within the trajectory of AI benchmarking:</p><ul><li><strong>Static QA benchmarks</strong> (GPQA, HLE): high-quality questions but no executable environment; increasingly saturated</li><li><strong>Terminal-Bench 2.0</strong>: executable environments for general tasks</li><li><strong>GDPval, APEX</strong>: realistic professional tasks</li><li><strong>FrontierScience</strong>: most directly related; introduces &quot;10-point rubrics with multiple independent criteria&quot; for open-ended scientific answers</li></ul><p>COMPOSITE-STEM builds on FrontierScience&#39;s rubric approach while adding cross-domain coverage, Harbor compatibility, and the AsymmetryZero grading framework.</p><h2 id="_2-task-composition" tabindex="-1">2. Task Composition <a class="header-anchor" href="#_2-task-composition" aria-label="Permalink to &quot;2. Task Composition&quot;">​</a></h2><h3 id="_2-1-domain-distribution" tabindex="-1">2.1 Domain Distribution <a class="header-anchor" href="#_2-1-domain-distribution" aria-label="Permalink to &quot;2.1 Domain Distribution&quot;">​</a></h3><p>The benchmark contains <strong>70 expert-written tasks</strong> distributed across four STEM domains:</p><table tabindex="0"><thead><tr><th>Domain</th><th>Tasks</th><th>Proportion</th></tr></thead><tbody><tr><td>Physics</td><td>20</td><td>28.6%</td></tr><tr><td>Chemistry</td><td>23</td><td>32.9%</td></tr><tr><td>Biology</td><td>20</td><td>28.6%</td></tr><tr><td>Mathematics</td><td>7</td><td>10.0%</td></tr><tr><td><strong>Total</strong></td><td><strong>70</strong></td><td><strong>100%</strong></td></tr></tbody></table><h3 id="_2-2-reference-assets" tabindex="-1">2.2 Reference Assets <a class="header-anchor" href="#_2-2-reference-assets" aria-label="Permalink to &quot;2.2 Reference Assets&quot;">​</a></h3><ul><li><strong>18 of 70 tasks</strong> include mounted reference files <ul><li>17 tasks with PNG images</li><li>1 task with PDF document</li></ul></li><li>Images serve as problem inputs (molecular diagrams, experimental data, microscopy images)</li><li>Provided as native multimodal input in the agent&#39;s first turn</li></ul><h3 id="_2-3-grading-distribution" tabindex="-1">2.3 Grading Distribution <a class="header-anchor" href="#_2-3-grading-distribution" aria-label="Permalink to &quot;2.3 Grading Distribution&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Grading Method</th><th>Tasks</th><th>Description</th></tr></thead><tbody><tr><td>Exact-match</td><td>35</td><td>Deterministic solutions; numeric or string comparison</td></tr><tr><td>LLM-jury (semantic)</td><td>34</td><td>Five frontier models vote on semantic correctness</td></tr><tr><td>Hybrid</td><td>1</td><td>Combines exact-match and LLM-jury</td></tr></tbody></table><p><strong>Rubric criteria</strong>: average 2.6 criteria per task; range 1–40 criteria (the outlier being a task with an unusually detailed rubric)</p><h3 id="_2-4-expert-curation-process" tabindex="-1">2.4 Expert Curation Process <a class="header-anchor" href="#_2-4-expert-curation-process" aria-label="Permalink to &quot;2.4 Expert Curation Process&quot;">​</a></h3><p>Contributors include doctoral researchers, distinguished faculty, postdoctoral scientists, and industry practitioners from leading institutions including MIT, Stanford, Cambridge, EPFL, and ETH Zurich. Many previously contributed to Humanity&#39;s Last Exam (HLE) and related frontier benchmarks. The team conducted &quot;detailed calls and review cycles&quot; with contributors to refine task design and validate scientific accuracy.</p><p>Tasks represent genuine scientific problem-solving rather than simplified proxies, requiring accurate application of domain-specific knowledge, appropriate use of scientific software libraries, and methodologically sound reasoning.</p><h2 id="_3-evaluation-methodology" tabindex="-1">3. Evaluation Methodology <a class="header-anchor" href="#_3-evaluation-methodology" aria-label="Permalink to &quot;3. Evaluation Methodology&quot;">​</a></h2><h3 id="_3-1-agent-harness-adapted-multimodal-terminus-2" tabindex="-1">3.1 Agent Harness: Adapted Multimodal Terminus-2 <a class="header-anchor" href="#_3-1-agent-harness-adapted-multimodal-terminus-2" aria-label="Permalink to &quot;3.1 Agent Harness: Adapted Multimodal Terminus-2&quot;">​</a></h3><p>Agents are evaluated using an adapted Terminus-2 harness within the Harbor framework:</p><ul><li>Supports multimodal inputs (images and text) in the first agent turn</li><li>Provides a terminal interface for code execution</li><li>Max turns: 10 per task</li></ul><h3 id="_3-2-sandbox-configuration" tabindex="-1">3.2 Sandbox Configuration <a class="header-anchor" href="#_3-2-sandbox-configuration" aria-label="Permalink to &quot;3.2 Sandbox Configuration&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Parameter</th><th>Value</th></tr></thead><tbody><tr><td>CPUs</td><td>1</td></tr><tr><td>Memory</td><td>2048 MB</td></tr><tr><td>Storage</td><td>10240 MB</td></tr><tr><td>Timeout</td><td>3600 seconds (1 hour)</td></tr><tr><td>Base image</td><td>Python 3.12-slim</td></tr><tr><td>Pre-installed tools</td><td>bash, git, curl, ripgrep, tmux, asciinema, litellm</td></tr><tr><td>Scientific packages</td><td>numpy, scipy, matplotlib, pandas, rdkit, biopython, etc.</td></tr></tbody></table><p>Agents can install additional packages during task execution using apt-get or pip, reflecting realistic scientific computing workflows.</p><h3 id="_3-3-grading-protocol-asymmetryzero" tabindex="-1">3.3 Grading Protocol: AsymmetryZero <a class="header-anchor" href="#_3-3-grading-protocol-asymmetryzero" aria-label="Permalink to &quot;3.3 Grading Protocol: AsymmetryZero&quot;">​</a></h3><p>AsymmetryZero operationalizes expert preferences as &quot;stable, auditable semantic contracts.&quot; The framework is designed for flexible, criterion-centric evaluation:</p><p><strong>Criterion specification</strong>: Each criterion defines:</p><ul><li>Weight (contribution to final score)</li><li>Grader type (exact-match or LLM-jury)</li><li>Instruction (what constitutes a passing response)</li></ul><p><strong>LLM-jury composition</strong> (five models via majority voting):</p><ul><li>DeepSeek-v3.2</li><li>GLM-5</li><li>GPT-oss-120b</li><li>Llama-3.3-70b-instruct</li><li>Kimi-K2.5</li></ul><p><strong>Aggregation</strong>: Strict majority voting for semantic criteria; weighted point aggregation normalized to Harbor&#39;s reward scalar (0.0–1.0).</p><p>The jury composition deliberately uses a diverse set of models to avoid bias toward any single model family&#39;s reasoning patterns.</p><h2 id="_4-model-results" tabindex="-1">4. Model Results <a class="header-anchor" href="#_4-model-results" aria-label="Permalink to &quot;4. Model Results&quot;">​</a></h2><h3 id="_4-1-leaderboard-pass-1" tabindex="-1">4.1 Leaderboard (Pass@1) <a class="header-anchor" href="#_4-1-leaderboard-pass-1" aria-label="Permalink to &quot;4.1 Leaderboard (Pass@1)&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Model</th><th>Pass Rate</th><th>Avg Time</th><th>Avg Steps</th><th>Input Tokens</th><th>Output Tokens</th></tr></thead><tbody><tr><td>Claude-opus-4.6</td><td><strong>21.4%</strong></td><td>11m 30s</td><td>5.6</td><td>156.0K</td><td>21.1K</td></tr><tr><td>Gemini-3.1-pro</td><td>18.6%</td><td>9m 16s</td><td>6.7</td><td>36.2K</td><td>18.4K</td></tr><tr><td>Grok-4.20-beta</td><td>5.7%</td><td>6m 3s</td><td>3.3</td><td>20.6K</td><td>4.7K</td></tr><tr><td>GPT-5.4</td><td>4.3%</td><td>6m 5s</td><td>2.6</td><td>17.4K</td><td>2.4K</td></tr></tbody></table><p>Top performer: Claude-opus-4.6 at 21.4%, indicating the benchmark effectively discriminates frontier model capabilities while leaving substantial room for improvement.</p><h3 id="_4-2-failure-mode-analysis" tabindex="-1">4.2 Failure Mode Analysis <a class="header-anchor" href="#_4-2-failure-mode-analysis" aria-label="Permalink to &quot;4.2 Failure Mode Analysis&quot;">​</a></h3><p>Failures are classified into two categories:</p><table tabindex="0"><thead><tr><th>Failure Type</th><th>Definition</th><th>Claude-opus-4.6</th><th>Gemini-3.1-pro</th><th>GPT-5.4</th><th>Grok-4.20-beta</th></tr></thead><tbody><tr><td><strong>Solution Error</strong></td><td>Submitted answer graded incorrect</td><td>63.0%</td><td>46.4%</td><td>90.9%</td><td>—</td></tr><tr><td><strong>Submission Error</strong></td><td>Failed to deliver valid artifact or hit max turns</td><td>37.0%</td><td>53.6%</td><td>9.1%</td><td>—</td></tr></tbody></table><p>Key observations:</p><ul><li>Claude and Gemini primarily fail via solution errors (wrong answers submitted) — they engage with problems but reason incorrectly</li><li>Gemini shows high submission error rate (53.6%), suggesting it more frequently fails to complete tasks within the turn budget</li><li>GPT-5.4 has 90.9% solution errors: it submits answers but they are mostly wrong</li><li>This pattern suggests GPT-5.4 and Grok lack the domain tool proficiency needed for correct solutions</li></ul><h3 id="_4-3-judge-agreement-patterns" tabindex="-1">4.3 Judge Agreement Patterns <a class="header-anchor" href="#_4-3-judge-agreement-patterns" aria-label="Permalink to &quot;4.3 Judge Agreement Patterns&quot;">​</a></h3><p>Stronger models show <strong>higher judge disagreement</strong> (more split jury votes), suggesting &quot;partially correct or borderline responses.&quot; Weaker models receive unanimous failures, indicating outright incorrect answers rather than grading bias.</p><p>This pattern validates the LLM-jury protocol: disagreement correlates with genuine solution quality rather than grader inconsistency.</p><h2 id="_5-behavioral-analysis" tabindex="-1">5. Behavioral Analysis <a class="header-anchor" href="#_5-behavioral-analysis" aria-label="Permalink to &quot;5. Behavioral Analysis&quot;">​</a></h2><h3 id="_5-1-tool-utilization" tabindex="-1">5.1 Tool Utilization <a class="header-anchor" href="#_5-1-tool-utilization" aria-label="Permalink to &quot;5.1 Tool Utilization&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Behavior</th><th>Claude-opus-4.6</th><th>Gemini-3.1-pro</th><th>GPT-5.4</th><th>Grok-4.20-beta</th></tr></thead><tbody><tr><td>Package installation (~% of runs)</td><td>~30%</td><td>~30%</td><td>~3%</td><td>~3%</td></tr><tr><td>Avg steps (tool-using runs)</td><td>~10</td><td>~10</td><td>—</td><td>—</td></tr><tr><td>Avg steps (minimal-tool runs)</td><td>—</td><td>—</td><td>~3.8</td><td>~4.5</td></tr><tr><td>Pass rate (minimal-tool runs)</td><td>~3–5%</td><td>~3–5%</td><td>~3–5%</td><td>~3–5%</td></tr></tbody></table><p><strong>Critical finding</strong>: Runs where agents install packages and actively use scientific libraries achieve pass rates around 10× higher than minimal-tool runs. Package installation (rdkit, biopython, etc.) is strongly predictive of success on domain-specific chemistry and biology tasks.</p><h3 id="_5-2-step-budget-analysis" tabindex="-1">5.2 Step Budget Analysis <a class="header-anchor" href="#_5-2-step-budget-analysis" aria-label="Permalink to &quot;5.2 Step Budget Analysis&quot;">​</a></h3><ul><li>Claude-opus-4.6: ~6.5 average steps (well within 10-turn budget)</li><li>Gemini-3.1-pro: ~8 average steps (highest engagement)</li><li>GPT-5.4: ~2.6 average steps (lowest; suggests early termination)</li><li>Grok-4.20-beta: ~3.3 average steps</li></ul><p>More steps correlate with better performance, consistent with extended reasoning chains and iterative tool use.</p><h2 id="_6-case-study-chemistry-task-0sl35u" tabindex="-1">6. Case Study: Chemistry Task 0sL35u <a class="header-anchor" href="#_6-case-study-chemistry-task-0sl35u" aria-label="Permalink to &quot;6. Case Study: Chemistry Task 0sL35u&quot;">​</a></h2><p><strong>Task</strong>: Determine the number of hydrogen atoms from a complex SMILES notation string representing a large organic molecule.</p><p><strong>Claude-opus-4.6 trajectory</strong> (PASS):</p><ol><li>Recognized SMILES as requiring chemical informatics library</li><li>Installed <code>python3-rdkit</code> via apt-get</li><li>Used RDKit to parse the SMILES string</li><li>Derived molecular formula: C280H350Br5Cl2I2N23O75S3</li><li><strong>Answer: 350</strong> ✓</li></ol><p><strong>GPT-5.4 trajectory</strong> (FAIL):</p><ol><li>Attempted rdkit installation — failed</li><li>Attempted openbabel installation — failed</li><li>Attempted pip installation paths — all failed</li><li>Pivoted to custom Python SMILES parser with hand-coded valence rules</li><li><strong>Answer: 399</strong> ✗ (exact-match grading)</li></ol><p><strong>Lesson</strong>: &quot;Persistence toward robust domain tool succeeded, while fragile hand-rolled workaround failed.&quot; This case illustrates that domain tool proficiency — knowing which library to use and how to install it — is a distinct capability from general coding skill.</p><h2 id="_7-limitations" tabindex="-1">7. Limitations <a class="header-anchor" href="#_7-limitations" aria-label="Permalink to &quot;7. Limitations&quot;">​</a></h2><p>The authors acknowledge several limitations:</p><ol><li><p><strong>External audit</strong>: The benchmark &quot;did not undergo a full external audit and quality-control and peer-review pipeline equivalent to a formal academic benchmark consortium.&quot; Contributors underwent vetting from previous benchmarking efforts (HLE, etc.), but this is not equivalent to formal peer review.</p></li><li><p><strong>Pass@1 only</strong>: Only single-run Pass@1 statistics are reported. Variance from repeated runs is not quantified, which may obscure stochastic performance differences.</p></li><li><p><strong>Fixed turn budget</strong>: The max_turns=10 constraint may limit agent performance, particularly for tasks that could benefit from extended iterative refinement.</p></li><li><p><strong>Jury subjectivity</strong>: Despite majority voting, LLM-jury grading introduces subjective judgment for borderline cases. The five-model jury mitigates but does not eliminate this.</p></li><li><p><strong>Domain balance</strong>: Mathematics is underrepresented (7 tasks vs 20–23 for other domains), potentially reducing statistical reliability of math-specific conclusions.</p></li></ol><h2 id="_8-conclusion" tabindex="-1">8. Conclusion <a class="header-anchor" href="#_8-conclusion" aria-label="Permalink to &quot;8. Conclusion&quot;">​</a></h2><p>COMPOSITE-STEM addresses the growing gap between saturated expert benchmarks and realistic agentic evaluation. By pairing expert-authored tasks with executable environments and flexible grading via AsymmetryZero, it provides a reliable evaluation signal for scientific agent capabilities.</p><p>Key findings:</p><ol><li>Current frontier models achieve only 21.4% on expert-curated scientific tasks — significant headroom remains</li><li>Tool proficiency (package installation, scientific library use) is strongly predictive of success</li><li>Extended reasoning and iterative tool use correlate with better performance</li><li>The LLM-jury protocol produces meaningful disagreement patterns that reflect genuine solution quality</li><li>Behavioral gaps between top and bottom models are large: Claude and Gemini vs GPT/Grok show ~5× performance difference</li></ol><p>COMPOSITE-STEM is open-sourced to encourage community adoption and further development of capable scientific agents.</p><h2 id="open-source-resources" tabindex="-1">Open-Source Resources <a class="header-anchor" href="#open-source-resources" aria-label="Permalink to &quot;Open-Source Resources&quot;">​</a></h2><ul><li><strong>Dataset</strong>: <a href="https://huggingface.co/datasets/portex/COMPOSITE-STEM" target="_blank" rel="noreferrer">https://huggingface.co/datasets/portex/COMPOSITE-STEM</a></li><li><strong>Harbor adapter</strong>: <a href="https://github.com/portex-ai/portex-composit-harbor-adapter" target="_blank" rel="noreferrer">https://github.com/portex-ai/portex-composit-harbor-adapter</a></li><li><strong>AsymmetryZero framework</strong>: <a href="https://github.com/portex-ai/asymmetry_zero" target="_blank" rel="noreferrer">https://github.com/portex-ai/asymmetry_zero</a> (MIT License)</li><li><strong>Portex Datalab</strong>: <a href="https://datalab.portexai.com" target="_blank" rel="noreferrer">https://datalab.portexai.com</a></li></ul><h2 id="references" tabindex="-1">References <a class="header-anchor" href="#references" aria-label="Permalink to &quot;References&quot;">​</a></h2><ul><li>Boiko et al. (2023). &quot;Emergent autonomous scientific research capabilities of large language models.&quot; arXiv:2304.05332.</li><li>Chan et al. (2024). &quot;MLE-bench: Evaluating Machine Learning Agents on Machine Learning Engineering.&quot; arXiv:2410.07095.</li><li>Hendrycks et al. (2021). &quot;Measuring Massive Multitask Language Understanding.&quot; ICLR 2021.</li><li>Jain et al. (2024). &quot;LiveCodeBench: Holistic and Contamination Free Evaluation of Large Language Models for Code.&quot; arXiv:2403.07974.</li><li>Kwa et al. (2025). &quot;GDPval: Evaluating agents on realistic professional tasks.&quot;</li><li>Lewkowycz et al. (2022). &quot;Solving quantitative reasoning problems with language models.&quot; NeurIPS 2022.</li><li>Phan et al. (2025). &quot;Humanity&#39;s Last Exam.&quot; arXiv:2501.14249.</li><li>Rein et al. (2023). &quot;GPQA: A Graduate-Level Google-Proof Q&amp;A Benchmark.&quot; arXiv:2311.12022.</li><li>Terminal-Bench Team (2025). &quot;Terminal-Bench 2.0: Evaluating Agents in Terminal Environments.&quot;</li><li>Waters et al. (2026). &quot;COMPOSITE-STEM: 70 Expert-Curated Agentic Tasks.&quot; arXiv:2604.09836.</li><li>White et al. (2025). &quot;FrontierScience: Open-ended Scientific Question Answering.&quot; arXiv:2502.07780.</li></ul>',77)])])}const p=e(o,[["render",n]]);export{g as __pageData,p as default};
